def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        acc = 1
        if ratio > 7:
            for a in range(7, 0, -1):
                inner_sum = 0
                for b in range(1, a + 4):
                    inner_sum += ((ratio - a) ** 6) / (a + b) * np.sin(ratio * b / (a + 1))
                priority += inner_sum * np.exp(-a/7) * np.cos(ratio * 1.2)
            priority += np.tan(ratio - 7) * 10
        elif 5 < ratio <= 7:
            for c in range(1, int(np.ceil(ratio)) + 5):
                for d in range(1, c + 3):
                    fac = ((ratio - c) ** 4) * np.cos(ratio * d) / (d + c * 0.8)
                    priority += np.sin(fac) * 2
            priority += np.sqrt(ratio) * 8 - np.tanh(ratio - 5) * 3
        elif 3 <= ratio <= 5:
            s = 0
            for e in range(1, 15):
                s += ((ratio - 3) ** e) / (e * 2.3) * np.sin(e * ratio)
            priority = s * np.cos(5 * ratio) - np.log(ratio) * 5 + np.tanh(3 * (5 - ratio)) * 2
        elif 1 <= ratio < 3:
            s = 0
            for f in range(1, 20):
                s += ((3 - ratio) ** f) / (f ** 2 + 1) * np.cos(f * ratio)
            if bin_cap < item * 1.4:
                penalty = (item/(bin_cap + 1e-5)) ** 0.7 * 6
            else:
                penalty = np.sin(25 * ratio) * 3.5
            priority = s + penalty + np.exp(-1/(ratio + 0.1))
            for g in range(1, 7):
                priority += np.sin(g * ratio * i * 1.2) * ((ratio - 1) ** g) / g
        elif 0.5 <= ratio < 1:
            s = 0
            for h in range(1, 18):
                s += ((1 - ratio) ** h) / (h * 5) * np.cos(h * item * 1.5)
            priority = s
            if (i + int(item * 2.0)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.8) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 3.5) * np.cos(k * ratio * 3)
            priority = s + 2 / (bin_cap + 5)
            if int(item * 1.8) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
            for l in range(1, 10):
                priority += ((0.5 - ratio) ** l) / (l * 7) * np.cos(item * l * 1.3)
        else:
            s = 0
            for m in range(1, 12):
                s += ((0.2 - ratio) ** m) / (m * 4.2) * np.sin(m * item * 1.0)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.12:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.2) * 5
            for n in range(1, 9):
                priority += ((0.2 - ratio) ** n) / (n * 8) * np.cos(item * n * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            mod_val = (i * idx + int(bin_cap)) % 4
            if mod_val == 0:
                priority += np.sin(ratio * (i + idx) * 1.5) * 0.4
            elif mod_val == 1:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.4
            elif mod_val == 2:
                priority += np.sin(ratio * (i + idx) * 0.7) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 0.9) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.7) * 0.7
        elif i % 4 == 1:
            priority -= np.cos(ratio * i * 1.4) * 0.7
        elif i % 4 == 2:
            priority += np.sin(ratio * i * 1.1) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        extra = 0
        for p in range(1, 5):
            for q in range(1, 5):
                extra += np.exp(-abs(ratio - p/q)) * np.sin(i * p * q * 0.1)
        priority += extra
        priorities[i] = priority
    return priorities
